# ✅ Two Pointers: Converge from ends (sorted array)
def two_sum_sorted(arr, target):
    left, right = 0, len(arr) - 1  # ✅ Pointers at ends

    while left < right:
        sum = arr[left] + arr[right]
        if sum == target:
            return [left, right]  # ✅ Found pair
        elif sum < target:
            left += 1  # ✅ Move left pointer (increase sum)
        else:
            right -= 1  # ✅ Move right pointer (decrease sum) [web:221][web:227]

    return [-1, -1]  # ❌ Not found

