# ✅ Binary Search: Eliminate half search space
def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # ✅ Search space

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid  # ✅ Found
        elif arr[mid] < target:
            left = mid + 1  # ✅ Search right half
        else:
            right = mid - 1  # ✅ Search left half [web:198][web:221]

    return -1  # ❌ Not found

