# ✅ DFS: Recursive exploration (paths, connectivity, cycles)
def dfs(graph, node, visited=set()):
    visited.add(node)  # ✅ Mark visited
    print(node)  # ✅ Process node

    for neighbor in graph[node]:  # ✅ Explore neighbors
        if neighbor not in visited:
            dfs(graph, neighbor, visited)  # ✅ Recurse [web:219][web:221]

# ✅ BFS: Queue-based exploration (shortest path)
from collections import deque

def bfs(graph, start):
    queue = deque([start])
    visited = {start}

    while queue:
        node = queue.popleft()  # ✅ Dequeue
        print(node)  # ✅ Process node

        for neighbor in graph[node]:  # ✅ Explore neighbors
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)  # ✅ Enqueue [web:219][web:221]

# Example: Number of Islands (DFS)
def num_islands(grid):
    count = 0
    for i in range(len(grid)):
        for j in range(len(grid[0])):
            if grid[i][j] == '1':
                dfs_island(grid, i, j)  # ✅ Mark entire island
                count += 1  # ✅ New island
    return count  # ✅ Count [web:219][web:221]

def dfs_island(grid, i, j):
    if i < 0 or i >= len(grid) or j < 0 or j >= len(grid[0]) or grid[i][j] == '0':
        return
    grid[i][j] = '0'  # ✅ Mark visited
    dfs_island(grid, i + 1, j)  # ✅ Down
    dfs_island(grid, i - 1, j)  # ✅ Up
    dfs_island(grid, i, j + 1)  # ✅ Right
    dfs_island(grid, i, j - 1)  # ✅ Left [web:219][web:221]

# ✅ DP: Overlapping subproblems, memoization
def edit_distance(word1, word2):
    n, m = len(word1), len(word2)
    dp = [[0] * (m + 1) for _ in range(n + 1)]  # ✅ DP table

    # Initialize base cases
    for i in range(n + 1):
        dp[i][0] = i  # ✅ Delete all
    for j in range(m + 1):
        dp[0][j] = j  # ✅ Insert all

    # Fill table (transition)
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if word1[i - 1] == word2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]  # ✅ No operation
            else:
                dp[i][j] = 1 + min(
                    dp[i - 1][j],  # ✅ Delete
                    dp[i][j - 1],  # ✅ Insert
                    dp[i - 1][j - 1]  # ✅ Replace
                ) [web:208][web:211][web:221]

    return dp[n][m]  # ✅ Edit distance [web:208][web:211][web:221]

