# ✅ DP: Longest Common Subsequence (text similarity, NLP)
def lcs(text1, text2):
    n, m = len(text1), len(text2)
    dp = [[0] * (m + 1) for _ in range(n + 1)]  # ✅ DP table

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if text1[i - 1] == text2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1  # ✅ Match: +1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])  # ✅ Mismatch: max [web:208][web:211][web:221]

    return dp[n][m]  # ✅ LCS length [web:208][web:211][web:221]

